create table daily_expenses
(
    id              varchar(255)                       not null comment '日表唯一ID'
        primary key,
    year            int                                not null comment '年份（关联月表）',
    month           int                                not null comment '月份（关联月表）',
    day             int                                not null comment '日期（1-31）',
    single_expense  decimal(10, 2)                     null comment '单次花销金额（0表示无消费）',
    expense_reason  varchar(50)                        null comment '花销原因（如零食、三餐）',
    expense_content varchar(100)                       null comment '花销内容物（如干脆面、猪脚饭）',
    daily_total     decimal(10, 2)                     null comment '当日花销合计',
    create_by       varchar(255)                       null comment '创建人',
    create_time     datetime default CURRENT_TIMESTAMP null comment '创建时间',
    update_by       varchar(255)                       null comment '更新人',
    update_time     datetime default CURRENT_TIMESTAMP null on update CURRENT_TIMESTAMP comment '更新时间'
)
    comment '用户每日花销明细表（含单次消费记录）';

create index year
    on daily_expenses (year, month);

